// PNB1 reassemble - mirrors pynode/nodes/NodeRedNode/bridge_protocol.py byte-for-byte.
// Input: msg.payload = Buffer (configure the upstream 'udp in' node with Output = buffer),
//        msg.ip / msg.port = sender address (set automatically by 'udp in').
// Output: one msg per fully-reassembled PNB1 message, or nothing (returns null) while
//         a message is still incomplete or the datagram is invalid.

const MAGIC = 'PNB1';
const HEADER_VERSION = 1;
const HEADER_SIZE = 16;
const FLAG_BINARY = 0x01;
const FLAG_JPEG = 0x02;
const DEFAULT_REASSEMBLY_TIMEOUT_MS = 2000;
const MAX_INCOMPLETE = 100;

const buf = msg.payload;
if (!Buffer.isBuffer(buf) || buf.length < HEADER_SIZE) {
    node.warn('PNB1: dropped short/non-buffer datagram');
    return null;
}

const magic = buf.toString('ascii', 0, 4);
if (magic !== MAGIC) {
    node.warn('PNB1: bad magic ' + magic);
    return null;
}
const version = buf.readUInt8(4);
const flags = buf.readUInt8(5);
const messageId = buf.readUInt32BE(6);
const chunkIndex = buf.readUInt16BE(10);
const chunkCount = buf.readUInt16BE(12);
const metaLength = buf.readUInt16BE(14);

if (chunkCount === 0 || chunkIndex >= chunkCount) {
    node.warn('PNB1: invalid chunk index/count ' + chunkIndex + '/' + chunkCount);
    return null;
}

const body = buf.slice(HEADER_SIZE);

// Per-node reassembly state, keyed by sender ip:port:messageId. Stored in node
// context so it survives between messages (but not between redeploys).
let pending = context.get('pnb1_pending') || {};
const senderKey = (msg.ip || '') + ':' + (msg.port || '') + ':' + messageId;
const now = Date.now();

// Sweep entries older than the reassembly timeout before handling this chunk.
for (const key of Object.keys(pending)) {
    if (now - pending[key].firstSeen > DEFAULT_REASSEMBLY_TIMEOUT_MS) {
        delete pending[key];
    }
}

let entry = pending[senderKey];
if (!entry) {
    const keys = Object.keys(pending);
    if (keys.length >= MAX_INCOMPLETE) {
        let oldestKey = null, oldestTime = Infinity;
        for (const k of keys) {
            if (pending[k].firstSeen < oldestTime) { oldestTime = pending[k].firstSeen; oldestKey = k; }
        }
        if (oldestKey) delete pending[oldestKey];
    }
    entry = { chunkCount: chunkCount, flags: flags, chunks: {}, meta: null, firstSeen: now };
    pending[senderKey] = entry;
}

if (chunkIndex === 0) {
    const metaBytes = body.slice(0, metaLength);
    try {
        entry.meta = JSON.parse(metaBytes.toString('utf8'));
    } catch (e) {
        node.warn('PNB1: failed to parse metadata JSON: ' + e.message);
        delete pending[senderKey];
        context.set('pnb1_pending', pending);
        return null;
    }
    entry.chunks[0] = body.slice(metaLength);
} else {
    entry.chunks[chunkIndex] = body;
}

let complete = true;
for (let i = 0; i < entry.chunkCount; i++) {
    if (!(i in entry.chunks)) { complete = false; break; }
}

if (!complete) {
    context.set('pnb1_pending', pending);
    return null;
}

delete pending[senderKey];
context.set('pnb1_pending', pending);

const parts = [];
for (let i = 0; i < entry.chunkCount; i++) { parts.push(entry.chunks[i]); }
const payloadBytes = Buffer.concat(parts);

const meta = entry.meta || {};
const payloadType = meta.payload_type;
let outPayload;
if (payloadType === 'json') {
    outPayload = payloadBytes.length ? JSON.parse(payloadBytes.toString('utf8')) : null;
} else if (payloadType === 'bytes' || payloadType === 'raw_numpy') {
    // raw_numpy has no JS/numpy equivalent - forwarded as a raw Buffer;
    // meta.dtype/meta.shape (see below) describe how to interpret it.
    outPayload = payloadBytes;
} else if (payloadType === 'jpeg') {
    outPayload = payloadBytes; // Buffer - wire straight into an image/preview node
} else {
    node.warn('PNB1: unknown payload_type ' + payloadType);
    return null;
}

const newMsg = {
    payload: outPayload,
    topic: meta.topic || '',
    _pnb1: { messageId: messageId, payloadType: payloadType, totalSize: meta.total_size }
};
if (payloadType === 'raw_numpy') {
    newMsg._pnb1.dtype = meta.dtype;
    newMsg._pnb1.shape = meta.shape;
}
if (meta.extra && typeof meta.extra === 'object') {
    for (const k of Object.keys(meta.extra)) {
        if (!(k in newMsg)) { newMsg[k] = meta.extra[k]; }
    }
}

return newMsg;

// PNB1 chunk+send - mirrors pynode/nodes/NodeRedNode/bridge_protocol.py byte-for-byte.
// Input: any msg (msg.payload / msg.topic).
// Output: an array of messages, one per UDP datagram, each with payload = Buffer -
//         wire this function's output directly into a single 'udp out' node
//         configured with the target host/port (must match the receiving
//         NodeRedInNode's bind host/port).

const MAGIC = 'PNB1';
const HEADER_VERSION = 1;
const HEADER_SIZE = 16;
const FLAG_BINARY = 0x01;
const FLAG_JPEG = 0x02;
const DEFAULT_CHUNK_SIZE = 60000;
const MTU_CHUNK_SIZE = 1400;

// Change to MTU_CHUNK_SIZE for WAN/VPN links. Any positive value works -
// chunk size only controls fragmentation, both ends decode the same way.
const CHUNK_SIZE = DEFAULT_CHUNK_SIZE;

function classifyPayload(payload) {
    if (Buffer.isBuffer(payload)) {
        const isJpeg = payload.length >= 2 && payload[0] === 0xFF && payload[1] === 0xD8;
        if (isJpeg) {
            return { payloadType: 'jpeg', bytes: payload, flags: FLAG_BINARY | FLAG_JPEG };
        }
        return { payloadType: 'bytes', bytes: payload, flags: FLAG_BINARY };
    }
    const json = JSON.stringify(payload === undefined ? null : payload);
    return { payloadType: 'json', bytes: Buffer.from(json, 'utf8'), flags: 0 };
}

const classified = classifyPayload(msg.payload);

const meta = { payload_type: classified.payloadType, total_size: classified.bytes.length };
if (msg.topic) { meta.topic = msg.topic; }

// Forward EVERY msg property besides payload/topic (underscore props like
// _msgid included) so the receiving NodeRedInNode replicates the message
// exactly. req/res (http nodes) are never serializable and always skipped;
// any other non-JSON-safe value skips just that key.
const RESERVED_KEYS = ['payload', 'topic', 'req', 'res'];
const extra = {};
for (const k of Object.keys(msg)) {
    if (RESERVED_KEYS.indexOf(k) !== -1) { continue; }
    let safe;
    try { safe = JSON.stringify(msg[k]); } catch (e) { continue; }
    if (safe === undefined) { continue; }
    extra[k] = msg[k];
}
if (Object.keys(extra).length > 0) { meta.extra = extra; }

let metaBytes;
try {
    metaBytes = Buffer.from(JSON.stringify(meta), 'utf8');
} catch (e) {
    delete meta.extra;
    metaBytes = Buffer.from(JSON.stringify(meta), 'utf8');
    node.warn('PNB1: extra msg properties were not JSON-safe; dropped from metadata');
}

if (metaBytes.length > 0xFFFF) {
    node.error('PNB1: metadata too large (' + metaBytes.length + ' bytes)', msg);
    return null;
}
const firstCapacity = CHUNK_SIZE - metaBytes.length;
if (firstCapacity < 0) {
    node.error('PNB1: metadata does not fit in one chunk; increase CHUNK_SIZE', msg);
    return null;
}

const payloadBytes = classified.bytes;
const chunk0Payload = payloadBytes.slice(0, firstCapacity);
const rest = payloadBytes.slice(firstCapacity);
const restChunks = [];
for (let i = 0; i < rest.length; i += CHUNK_SIZE) {
    restChunks.push(rest.slice(i, i + CHUNK_SIZE));
}
const chunkCount = 1 + restChunks.length;
if (chunkCount > 0xFFFF) {
    node.error('PNB1: message too large (' + chunkCount + ' chunks)', msg);
    return null;
}

// Per-node monotonically increasing message id, wraps at 2**32 (matches
// bridge_protocol.next_message_id).
let messageId = context.get('pnb1_message_id');
messageId = (messageId === undefined) ? 0 : (messageId + 1) % 0x100000000;
context.set('pnb1_message_id', messageId);

function buildHeader(flags, chunkIndex, metaLen) {
    const header = Buffer.alloc(HEADER_SIZE);
    header.write(MAGIC, 0, 4, 'ascii');
    header.writeUInt8(HEADER_VERSION, 4);
    header.writeUInt8(flags, 5);
    header.writeUInt32BE(messageId, 6);
    header.writeUInt16BE(chunkIndex, 10);
    header.writeUInt16BE(chunkCount, 12);
    header.writeUInt16BE(metaLen, 14);
    return header;
}

const datagrams = [];
datagrams.push(Buffer.concat([buildHeader(classified.flags, 0, metaBytes.length), metaBytes, chunk0Payload]));
for (let i = 0; i < restChunks.length; i++) {
    datagrams.push(Buffer.concat([buildHeader(classified.flags, i + 1, 0), restChunks[i]]));
}

// Fan out as separate messages, one per datagram; wire straight into a
// single 'udp out' node so each becomes exactly one UDP packet.
return [datagrams.map(function (d) { return { payload: d }; })];

// Optional: promote the bridged message to the top level so the Node-RED msg
// replicates the PyNode msg exactly (payload/topic/_msgid/... as msg.*).
// Delete this node if you prefer the whole object in msg.payload.
var m = msg.payload;
if (m && typeof m === 'object' && !Array.isArray(m) && 'payload' in m) {
    return m;
}
return msg;

// One JSON object per line; the newline is the framing. topic is optional.
msg.payload = JSON.stringify({payload: msg.payload, topic: msg.topic || ''}) + "
";
return msg;
